import{_ as a,o as d,c as s,a4 as r}from"./chunks/framework.E9a65_Io.js";const i=JSON.parse('{"title":"齿轮总览","description":"","frontmatter":{},"headers":[],"relativePath":"gears.md","filePath":"gears.md"}'),e={name:"gears.md"};function n(p,t,l,g,o,c){return d(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="齿轮总览" tabindex="-1">齿轮总览 <a class="header-anchor" href="#齿轮总览" aria-label="Permalink to &quot;齿轮总览&quot;">​</a></h1><p>齿轮是笨猫探穴中非常重要的一部分，它们提供各种增益效果，帮助你在宏大的挖掘之旅中前进。整个游戏共有 40 个齿轮，分布在各个世界中。世界一有 13 个，世界二有 13 个，子领域一有 7 个，水水世界有 2 个，银河有 5 个。每个齿轮都有自己独特的功能——有些提供幸运加成，有些提供挖掘速度加成，还有些赋予你获取一切的能力。种类丰富，让你有很多机会打造最强配置。</p><p>最终所有齿轮的配方都会收录在这里。目前，这里仅列出每个齿轮的功能、名称和获取方式。</p><h3 id="世界一齿轮" tabindex="-1">世界一齿轮 <a class="header-anchor" href="#世界一齿轮" aria-label="Permalink to &quot;世界一齿轮&quot;">​</a></h3><table tabindex="0"><thead><tr><th>齿轮</th><th>效果</th></tr></thead><tbody><tr><td><span class="gear-red">RNG 操纵器</span></td><td>基础幸运 +0.3 倍</td></tr><tr><td><span class="gear-teal">临时加速器</span></td><td>挖掘速度延迟从 25ms 降至 20ms</td></tr><tr><td><span class="grad-text g-time">时间失稳器</span></td><td>离线进度奖励 +0.2 倍</td></tr><tr><td><span class="grad-text g-tracker">矿石追踪器</span></td><td>允许访问矿石追踪菜单，指引最近发出生成消息的稀有矿石（<a href="./antique.html">古董+</a>）</td></tr><tr><td><span class="grad-text g-cand">真烛晶</span></td><td>技能幸运提升 1.1 倍</td></tr><tr><td><span class="grad-text g-vitriol">真硫酸</span></td><td>挖掘速度延迟从 25ms 降至 15ms</td></tr><tr><td><span class="grad-text g-siphon">能量虹吸器</span></td><td>激活后挖掘速度 -3ms，持续 10s，可叠加 5 次（每次 +5s）。冷却 5s。挖掘<a href="./antique.html">古董+</a>激活</td></tr><tr><td><span class="grad-text g-sugar">糖分冲刺</span></td><td>技能触发率提高 20%</td></tr><tr><td><span class="grad-text g-event">事件管理器</span></td><td>解锁事件管理器按钮和菜单</td></tr><tr><td><span class="grad-text g-inf">无限收集器</span></td><td>立即挖掘任何生成的稀有矿石（天界除外）</td></tr><tr><td><span class="grad-text g-layer">地层物质化器</span></td><td>每挖掘一个方块，额外给予一个当前地层方块（可复制）</td></tr><tr><td><span class="grad-text g-fortune">时运 III 书</span></td><td>技能幸运提升 1.6 倍（与真烛晶叠加）</td></tr><tr><td><span class="grad-text g-haste">急迫 II 信标</span></td><td>挖掘速度延迟从 25ms 降至 10ms</td></tr><tr><td><span class="grad-text g-abyss">深渊跳跃者</span></td><td>跳过空白格子，一次最多 25 格。Shift 禁用。1/250 概率额外移动 50 方块</td></tr><tr><td><span class="grad-text g-disengage">脱离增量器</span></td><td>离线进度奖励 +0.45 倍</td></tr><tr><td><span class="grad-text g-silly">SILLYYYY</span></td><td>在重复地层随机位置生成愚蠢/蛋糕地层</td></tr></tbody></table><h3 id="世界二齿轮" tabindex="-1">世界二齿轮 <a class="header-anchor" href="#世界二齿轮" aria-label="Permalink to &quot;世界二齿轮&quot;">​</a></h3><table tabindex="0"><thead><tr><th>齿轮</th><th>效果</th></tr></thead><tbody><tr><td><span class="grad-text g2-quantum">量子纠缠器</span></td><td>每秒增加 25 个方块的速度</td></tr><tr><td><span class="grad-text g2-logic">逻辑随机化器</span></td><td>幸运 +0.25 倍（可叠加）</td></tr><tr><td><span class="grad-text g2-storm">风暴跑鞋</span></td><td>挖掘速度 -3ms（可叠加）</td></tr><tr><td><span class="grad-text g2-artifice">巧计歼灭者</span></td><td>幸运 +0.35 倍（可叠加）</td></tr><tr><td><span class="grad-text g2-replicator">改用途复制器</span></td><td>75% 概率复制普通等级矿石（1/1 - 1/749k）</td></tr><tr><td><span class="grad-text g2-cavern">洞穴电容器</span></td><td>赋予世界二洞穴生成能力（生成世界一的洞穴）</td></tr><tr><td><span class="grad-text g2-subatomic">亚原子叠加器</span></td><td>每秒增加 75 个方块的速度（与纠缠器叠加）</td></tr><tr><td><span class="grad-text g2-vacuum">高功率吸尘器</span></td><td>挖掘地层方块时 50% 概率额外获得 2 个地层方块</td></tr><tr><td><span class="grad-text g2-speedcap">解锁速度上限</span></td><td>挖掘速度 -5ms（可叠加）</td></tr><tr><td><span class="grad-text g2-inf2">无限收集器 II</span></td><td>世界二版无限收集器，立即挖掘除天界外所有矿石</td></tr><tr><td><span class="grad-text g2-clover">三叶草撤销</span></td><td>幸运 +2.5 倍（可叠加）</td></tr><tr><td><span class="grad-text g2-structural">结构服务</span></td><td>挖掘速度 -7ms，自动挖掘移动 +2 方块。与所有速度增益叠加</td></tr><tr><td><span class="grad-text g2-statamp">统计放大器</span></td><td>所有幸运 ×（镐子幸运+1）的 5%，只增不减</td></tr><tr><td><span class="grad-text g2-oblivion">湮灭破碎者</span></td><td>允许深渊石洞穴以 1/1000 概率生成</td></tr></tbody></table><h3 id="子领域一齿轮" tabindex="-1">子领域一齿轮 <a class="header-anchor" href="#子领域一齿轮" aria-label="Permalink to &quot;子领域一齿轮&quot;">​</a></h3><table tabindex="0"><thead><tr><th>齿轮</th><th>效果</th></tr></thead><tbody><tr><td><span class="grad-text g3-replicator">复制器原型</span></td><td>10% 概率复制 1/750k+ 稀有矿石</td></tr><tr><td><span class="grad-text g3-hyperdrive">超光速加速器</span></td><td>技能触发概率 +15%</td></tr><tr><td><span class="grad-text g3-automaton">超能自动机</span></td><td>自动循环激活强化，-25% 冷却，+50% 激活时间</td></tr><tr><td><span class="grad-text g3-alteration">变更重复器</span></td><td>普通矿石额外判定一次变体</td></tr><tr><td><span class="grad-text g3-stratum">地层无限器</span></td><td>挖掘地层方块 5% 概率获得 30 倍奖励</td></tr><tr><td><span class="grad-text g3-biome">生物群系附魔师</span></td><td>洞穴类型加成 1.75 倍</td></tr><tr><td><span class="grad-text g3-reaper">天界收割者</span></td><td>任何无限收集器可挖掘天界矿石</td></tr></tbody></table><h3 id="水水世界齿轮" tabindex="-1">水水世界齿轮 <a class="header-anchor" href="#水水世界齿轮" aria-label="Permalink to &quot;水水世界齿轮&quot;">​</a></h3><table tabindex="0"><thead><tr><th>齿轮</th><th>效果</th></tr></thead><tbody><tr><td><span class="grad-text g4-lightspeed">光速模拟器</span></td><td>移动重复次数 1.75 倍（向上取整）</td></tr><tr><td><span class="grad-text g4-exponential">增强指数性</span></td><td>幸运 = 幸运^1.035</td></tr></tbody></table><h3 id="银河齿轮" tabindex="-1">银河齿轮 <a class="header-anchor" href="#银河齿轮" aria-label="Permalink to &quot;银河齿轮&quot;">​</a></h3><table tabindex="0"><thead><tr><th>齿轮</th><th>效果</th></tr></thead><tbody><tr><td><span class="grad-text g5-potential">潜能倍增器</span></td><td>普通技能 ×4，模拟技能 ×2</td></tr><tr><td><span class="grad-text g5-electrify">电击传播器</span></td><td>技能触发率 +50%</td></tr><tr><td><span class="grad-text g5-rose">遗忘玫瑰石英壳</span></td><td>每分钟随机增益：1.4x 幸运 / 2x 触发率 / +25 移动重复</td></tr><tr><td><span class="grad-text g5-armband">无尽梦境臂环</span></td><td>1/2 触发率，模拟生成量 ×3</td></tr></tbody></table><h3 id="隐藏戒指齿轮-银河" tabindex="-1">隐藏戒指齿轮（银河） <a class="header-anchor" href="#隐藏戒指齿轮-银河" aria-label="Permalink to &quot;隐藏戒指齿轮（银河）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>戒指</th><th>效果</th></tr></thead><tbody><tr><td><span class="grad-text g5r-life">生命之戒</span></td><td>基础幸运 ×1.5。<em>&quot;我的生命始于此处……&quot;</em></td></tr><tr><td><span class="grad-text g5r-intel">智慧之戒</span></td><td>10% 概率 +500,000 模拟技能量。<em>&quot;我够聪明能来到这里吗……&quot;</em></td></tr><tr><td><span class="grad-text g5r-sound">声音之戒</span></td><td>每拥有一个超维矿石，幸运 +0.01x（无上限）。<em>&quot;我听到了奇怪的音乐……&quot;</em></td></tr><tr><td><span class="grad-text g5r-unknown">未知之戒</span></td><td>允许在子领域一使用虫洞灭绝者。<em>&quot;我不该在这里……&quot;</em></td></tr><tr><td><span class="grad-text g5r-creation">创世之戒</span></td><td>+50 移动重复次数。<em>&quot;此地诞生了天空中的星辰……&quot;</em></td></tr><tr><td><span class="grad-text g5r-fire">火焰之戒</span></td><td>幸运 × (游戏时长分钟 × 0.01) + 1。<em>&quot;这里好热……&quot;</em></td></tr></tbody></table><hr><p><em>由 <a href="https://the-silly-caverns.fandom.com/wiki/Gears" target="_blank" rel="noreferrer">笨猫探穴 Wiki</a> 汉化</em></p>',17)])])}const x=a(e,[["render",n]]);export{i as __pageData,x as default};
